from crewai import Agent, Task, Crew
from collections import defaultdict

def detect_delegation_loops(crew):
    delegation_graph = defaultdict(list)
    for task in crew.tasks:
        if hasattr(task, 'delegate_to'):
            delegation_graph[task.agent.name].append(task.delegate_to.name)

    visited = set()
    def has_cycle(node):
        if node in visited:
            return True
        visited.add(node)
        for neighbor in delegation_graph[node]:
            if has_cycle(neighbor):
                return True
        visited.remove(node)
        return False

    for agent in crew.agents:
        if has_cycle(agent.name):
            return f"LOOP DETECTED: {agent.name} -> cycle"
    return "No loops detected"

def trace_hallucinated_outputs(task_history):
    hallucinations = []
    for i, task in enumerate(task_history):
        if 'tools_used' in task.output:
            for tool_call in task.output['tools_used']:
                if 'hallucinated' in tool_call.get('response', '').lower() or len(tool_call.get('response', '')) < 10:
                    hallucinations.append({
                        'task': i,
                        'agent': task.agent,
                        'tool': tool_call['name'],
                        'suspicious_output': tool_call['response'][:100]
                    })
    return hallucinations if hallucinations else []

from difflib import SequenceMatcher

def analyze_task_drift(original_task, agent_interpretations):
    original_text = original_task.description
    drift_scores = []
    for agent_name, interpretation in agent_interpretations.items():
        similarity = SequenceMatcher(None, original_text, interpretation).ratio()
        if similarity < 0.7:
            drift_scores.append({
                'agent': agent_name,
                'drift_score': similarity,
                'original': original_text[:50],
                'interpretation': interpretation[:50]
            })
    return drift_scores

