from crewai import Agent
from pydantic import BaseModel, Field

class ValidatedToolOutput(BaseModel):
    is_valid: bool = Field(..., description="Must confirm output validity")
    confidence: float = Field(ge=0.0, le=1.0)
    raw_output: str
    validation_reason: str

class ToolValidatorAgent(Agent):
    def validate_tool_output(self, tool_output):
        validation = self.execute_task(f"Validate this tool output: {tool_output}")
        return ValidatedToolOutput.parse_raw(validation)

# In crew workflow
validator = ToolValidatorAgent(...)
if not validator.validate_tool_output(tool_result).is_valid:
    raise ValueError("Invalid tool output detected")
